(4, 'After Effects Plugin', 'after-effects-plugin', 'Powerful plugins and extensions to supercharge your After Effects workflow', 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=400&q=80');

-- Products - Only animation/video products + a few non-video
INSERT OR IGNORE INTO products (id, name, slug, description, price, compare_price, image_url, images, category_id, stock, rating, reviews_count, featured, media_type, video_url, preview_url, preview_description, file_size, duration) VALUES

-- Video Products (Animation / Motion Graphics Focus)
(13, 'Cinematic Nature Reel — 4K', 'cinematic-nature-reel', 'A stunning collection of cinematic nature footage captured in 4K resolution. Features breathtaking landscapes, wildlife encounters, and atmospheric time-lapses from around the world. Perfect for video editing, content creation, or personal enjoyment.', 29.99, 49.99, 'https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=600&q=80', '["https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=600&q=80","https://images.unsplash.com/photo-1500382017468-9049fed747ef?w=600&q=80"]', 7, 999, 4.9, 45, 1, 'video', 'https://example.com/videos/nature-reel-4k.mp4', 'https://example.com/previews/nature-reel-preview.mp4', 'Watch a 30-second preview of this stunning 4K nature collection. Full reel runs 12 minutes with 20 unique scenes.', 2.4, 720),

(14, 'Urban Time-lapse Compilation', 'urban-timelapse', 'Mesmerizing time-lapse footage of cityscapes from New York, Tokyo, London, and Dubai. Captured over 6 months in stunning 4K HDR. Includes day-to-night transitions, traffic flows, and weather phenomena.', 24.99, 39.99, 'https://images.unsplash.com/photo-1519501025264-65ba15a82390?w=600&q=80', '["https://images.unsplash.com/photo-1519501025264-65ba15a82390?w=600&q=80","https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=600&q=80"]', 7, 999, 4.7, 32, 1, 'video', 'https://example.com/videos/urban-timelapse.mp4', 'https://example.com/previews/urban-timelapse-preview.mp4', 'Preview this 8-minute urban time-lapse journey across 4 major world cities in breathtaking 4K HDR.', 1.8, 480),

(15, 'Abstract Motion Graphics Pack', 'abstract-motion-graphics', 'A dynamic collection of 50+ abstract motion graphics elements. Includes fluid shapes, particle systems, geometric transitions, and glowing orbs. Perfect for intro sequences, social media content, and music visualizers.', 34.99, 54.99, 'https://images.unsplash.com/photo-1558591710-4b4a1ae0f04d?w=600&q=80', '["https://images.unsplash.com/photo-1558591710-4b4a1ae0f04d?w=600&q=80","https://images.unsplash.com/photo-1633356122102-3fe601e05bd2?w=600&q=80"]', 7, 999, 4.8, 78, 1, 'video', 'https://example.com/videos/abstract-motion.mp4', 'https://example.com/previews/abstract-motion-preview.mp4', 'Preview 10 of the 50+ abstract motion elements included in this pack. Full pack features 4K resolution with alpha channel support.', 3.2, 360),

(16, '3D Logo Reveal Templates', '3d-logo-reveal', 'Professional 3D logo reveal animation template pack. Features 20 cinematic logo animations with metallic shatter, particle burst, neon glow, and smooth morph transitions. Drag-and-drop your logo in After Effects or Premiere Pro.', 44.99, 69.99, 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=600&q=80', '["https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=600&q=80","https://images.unsplash.com/photo-1633356122102-3fe601e05bd2?w=600&q=80"]', 7, 999, 4.9, 112, 1, 'video', 'https://example.com/videos/logo-reveal.mp4', 'https://example.com/previews/logo-reveal-preview.mp4', 'Watch a demo reel of all 20 logo reveal styles. Each template includes fully customizable After Effects project files.', 4.1, 120),

(17, 'Social Media Story Templates', 'social-story-templates', '30 animated Instagram/Facebook story templates with trendy transitions, animated stickers, and dynamic text animations. Includes both vertical (9:16) and square (1:1) formats. Easy to customize with your own photos and text.', 19.99, 29.99, 'https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=600&q=80', '["https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=600&q=80","https://images.unsplash.com/photo-1611605698335-8b156f0504bf?w=600&q=80"]', 7, 999, 4.6, 56, 0, 'video', 'https://example.com/videos/social-templates.mp4', 'https://example.com/previews/social-templates-preview.mp4', 'See all 30 social media templates in action. Includes Canva and Premiere Pro compatible formats.', 0.8, 60),

(18, 'Animated Typography Pack', 'animated-typography', '50 premium animated typography presets with kinetic text animations, reveal effects, and dynamic title sequences. Features elegant serif, modern sans-serif, and playful display font animations. Ideal for lyric videos, presentations, and social content.', 27.99, 39.99, 'https://images.unsplash.com/photo-1563986768609-322da13575f2?w=600&q=80', '["https://images.unsplash.com/photo-1563986768609-322da13575f2?w=600&q=80","https://images.unsplash.com/photo-1579783902614-a3fb3927b6a5?w=600&q=80"]', 7, 999, 4.7, 89, 1, 'video', 'https://example.com/videos/typography-pack.mp4', 'https://example.com/previews/typography-preview.mp4', 'Preview 15 of the 50 typography presets. Full pack includes MOGRT files for Premiere Pro and After Effects.', 1.5, 180),

(19, 'Particle Effects Library', 'particle-effects', 'Over 100 particle effect presets including fire, smoke, sparkles, bubbles, snow, rain, magical dust, and abstract particle trails. All effects are fully customizable with color, speed, and density controls. Compatible with major compositing software.', 39.99, 59.99, 'https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&q=80', '["https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&q=80","https://images.unsplash.com/photo-1633356122102-3fe601e05bd2?w=600&q=80"]', 7, 999, 4.8, 134, 1, 'video', 'https://example.com/videos/particle-effects.mp4', 'https://example.com/previews/particle-preview.mp4', 'Watch a showcase of all 100+ particle effects. Each effect includes a video tutorial for customization.', 2.8, 540),

(20, 'Cinematic Transitions Pack', 'cinematic-transitions', '60 professional video transitions for stunning scene changes. Includes smooth wipes, zoom bumps, light leaks, lens flares, glitch effects, and whip pans. Designed for storytelling — each transition adds emotional weight to your edit.', 22.99, 34.99, 'https://images.unsplash.com/photo-1536240478700-b869070f9279?w=600&q=80', '["https://images.unsplash.com/photo-1536240478700-b869070f9279?w=600&q=80","https://images.unsplash.com/photo-1519501025264-65ba15a82390?w=600&q=80"]', 7, 999, 4.6, 67, 0, 'video', 'https://example.com/videos/transitions.mp4', 'https://example.com/previews/transitions-preview.mp4', 'Demo reel of all 60 transitions. Drag-and-drop compatible with Premiere Pro, Final Cut Pro, and DaVinci Resolve.', 1.2, 240),

(21, 'Lower Thirds & Titles Bundle', 'lower-thirds-bundle', 'A complete bundle of 80 animated lower thirds, title cards, and callout graphics. Features clean corporate, sporty dynamic, elegant wedding, and modern YouTube styles. Each comes with customizable colors, fonts, and animation durations.', 32.99, 49.99, 'https://images.unsplash.com/photo-1579783902614-a3fb3927b6a5?w=600&q=80', '["https://images.unsplash.com/photo-1579783902614-a3fb3927b6a5?w=600&q=80","https://images.unsplash.com/photo-1563986768609-322da13575f2?w=600&q=80"]', 7, 999, 4.5, 43, 0, 'video', 'https://example.com/videos/lower-thirds.mp4', 'https://example.com/previews/lower-thirds-preview.mp4', 'See examples from all 80 lower third designs across 5 style categories. MOGRT files included.', 0.9, 300),

(22, 'Vlog Editing Starter Pack', 'vlog-editing-pack', 'Everything you need to start editing professional vlogs: 40 animated overlays, 20 transition effects, 30 sound effects, 10 color LUTs, and 5 title templates. Designed for YouTube, TikTok, and Instagram content creators who want polished, engaging videos.', 17.99, 27.99, 'https://images.unsplash.com/photo-1611162616475-46b635cb6868?w=600&q=80', '["https://images.unsplash.com/photo-1611162616475-46b635cb6868?w=600&q=80","https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=600&q=80"]', 7, 999, 4.7, 198, 1, 'video', 'https://example.com/videos/vlog-pack.mp4', 'https://example.com/previews/vlog-pack-preview.mp4', 'Watch a complete before/after comparison of raw footage with the Vlog Editing Starter Pack applied.', 1.1, 420),

(23, 'Explainer Video Toolkit', 'explainer-video-toolkit', 'Create professional explainer videos with this comprehensive toolkit. Includes 50+ animated icons, whiteboard animation elements, character rigs, call-to-action animations, and animated charts. Perfect for business presentations, product demos, and educational content.', 37.99, 54.99, 'https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&q=80', '["https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&q=80","https://images.unsplash.com/photo-1558591710-4b4a1ae0f04d?w=600&q=80"]', 7, 999, 4.6, 92, 0, 'video', 'https://example.com/videos/explainer-toolkit.mp4', 'https://example.com/previews/explainer-preview.mp4', 'Preview the explainer toolkit with sample scenes from a product demo video created using the assets.', 2.1, 600),

(24, 'Glitch & Distortion FX', 'glitch-fx-pack', '40 intense glitch and distortion effects for adding edge to your videos. Includes digital glitch, screen damage, VHS distortion, chromatic aberration, scan lines, and static interference. Each effect has adjustable intensity controls.', 15.99, 24.99, 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=600&q=80', '["https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=600&q=80","https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&q=80"]', 7, 999, 4.4, 34, 0, 'video', 'https://example.com/videos/glitch-fx.mp4', 'https://example.com/previews/glitch-preview.mp4', 'See all 40 glitch effects in action. Compatible with Adobe After Effects and Premiere Pro.', 0.6, 120),

(25, 'Animated Infographic Bundle', 'animated-infographics', '30 data visualization animation templates including animated bar charts, line graphs, pie charts, progress bars, counters, and comparison sliders. Perfect for business presentations, YouTube analytics videos, and data-driven content.', 29.99, 44.99, 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=600&q=80', '["https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=600&q=80","https://images.unsplash.com/photo-1563986768609-322da13575f2?w=600&q=80"]', 7, 999, 4.5, 51, 1, 'video', 'https://example.com/videos/infographic-bundle.mp4', 'https://example.com/previews/infographic-preview.mp4', 'Watch a demo of all 30 infographic templates with data animation in action.', 1.9, 360),


-- After Effects Plugin Products
(26, 'Motion Blur Pro — Realistic Blur Plugin', 'motion-blur-pro', 'Take your motion graphics to the next level with Motion Blur Pro. This powerful After Effects plugin delivers cinema-grade motion blur with pixel-accurate rendering, multi-frame sampling, and intelligent motion vector analysis. Perfect for adding smooth, natural-looking blur to animations, text reveals, and complex compositions.', 49.99, 69.99, 'https://images.unsplash.com/photo-1579783902614-a3fb3927b6a5?w=600&q=80', '["https://images.unsplash.com/photo-1579783902614-a3fb3927b6a5?w=600&q=80","https://images.unsplash.com/photo-1558591710-4b4a1ae0f04d?w=600&q=80"]', 8, 999, 4.8, 76, 1, 'digital', NULL, NULL, NULL, 0.5, NULL),

(27, 'Color Grading Suite — Pro Color Tools', 'color-grading-suite', 'Professional color grading toolkit for After Effects featuring 120+ LUTs, real-time scopes, skin tone protection, and advanced color wheels. Includes film emulation presets for Hollywood-grade looks. Streamline your color workflow with an intuitive layer-based grading system.', 39.99, 54.99, 'https://images.unsplash.com/photo-1563986768609-322da13575f2?w=600&q=80', '["https://images.unsplash.com/photo-1563986768609-322da13575f2?w=600&q=80","https://images.unsplash.com/photo-1633356122102-3fe601e05bd2?w=600&q=80"]', 8, 999, 4.7, 124, 1, 'digital', NULL, NULL, NULL, 0.8, NULL),

(28, 'Keylight Ultra — Advanced Keying Engine', 'keylight-ultra', 'Next-generation chroma keying plugin for After Effects that handles even the toughest green screen footage. Features AI-powered edge detection, spill suppression, light wrap, and hair detail preservation. Process footage 3x faster than native keying with superior results.', 59.99, 79.99, 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=600&q=80', '["https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=600&q=80","https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&q=80"]', 8, 999, 4.9, 203, 1, 'digital', NULL, NULL, NULL, 1.2, NULL),

(29, 'Particle Studio — 3D Particle System', 'particle-studio', 'Create stunning particle effects with Particle Studio — the most powerful 3D particle system plugin for After Effects. Features GPU-accelerated rendering, 200+ presets, fluid dynamics, soft body physics, and OBJ emission. From elegant sparkles to explosive simulations, bring your visions to life.', 44.99, 64.99, 'https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&q=80', '["https://images.unsplash.com/photo-1550745165-9bc0b252726f?w=600&q=80","https://images.unsplash.com/photo-1558591710-4b4a1ae0f04d?w=600&q=80"]', 8, 999, 4.8, 167, 1, 'digital', NULL, NULL, NULL, 2.1, NULL),

(30, 'Transition Builder — Custom Transitions', 'transition-builder', 'Design and customize professional video transitions with an intuitive node-based editor. Transition Builder for After Effects includes 150+ drag-and-drop transition presets, keyframe-linked parameters, and real-time preview. Create unique transitions that perfectly match your brand and style.', 34.99, 49.99, 'https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&q=80', '["https://images.unsplash.com/photo-1558618666-fcd25c85f82e?w=600&q=80","https://images.unsplash.com/photo-1536240478700-b869070f9279?w=600&q=80"]', 8, 999, 4.6, 98, 1, 'digital', NULL, NULL, NULL, 0.6, NULL);

